import { jest } from '@jest/globals';
import CommandExecutor from '../src/executor/CommandExecutor.js';

describe('CommandExecutor', () => {
  let executor;

  beforeEach(() => {
    executor = new CommandExecutor({
      timeout: 5000,
      cwd: '/test/dir'
    });
  });

  describe('constructor', () => {
    it('should initialize with default options', () => {
      const defaultExecutor = new CommandExecutor();
      expect(defaultExecutor.timeout).toBe(30000);
      expect(defaultExecutor.cwd).toBe(process.cwd());
    });

    it('should initialize with custom options', () => {
      expect(executor.timeout).toBe(5000);
      expect(executor.cwd).toBe('/test/dir');
    });
  });

  describe('isDangerous', () => {
    it('should detect rm -rf as dangerous', () => {
      expect(executor.isDangerous('rm -rf /')).toBe(true);
      expect(executor.isDangerous('rm -rf /home')).toBe(true);
    });

    it('should detect sudo as dangerous', () => {
      expect(executor.isDangerous('sudo apt-get install')).toBe(true);
    });

    it('should detect chmod as dangerous', () => {
      expect(executor.isDangerous('chmod 777 file.txt')).toBe(true);
    });

    it('should detect wget and curl as dangerous', () => {
      expect(executor.isDangerous('wget http://example.com')).toBe(true);
      expect(executor.isDangerous('curl http://example.com')).toBe(true);
    });

    it('should not flag safe commands as dangerous', () => {
      expect(executor.isDangerous('ls -la')).toBe(false);
      expect(executor.isDangerous('cat file.txt')).toBe(false);
      expect(executor.isDangerous('echo "hello"')).toBe(false);
      expect(executor.isDangerous('npm install')).toBe(false);
    });

    it('should be case insensitive', () => {
      expect(executor.isDangerous('RM -RF /')).toBe(true);
      expect(executor.isDangerous('SUDO apt-get')).toBe(true);
    });
  });

  describe('getDangerousCommands', () => {
    it('should return list of dangerous commands', () => {
      const dangerous = executor.getDangerousCommands();
      expect(Array.isArray(dangerous)).toBe(true);
      expect(dangerous.length).toBeGreaterThan(0);
      expect(dangerous).toContain('rm -rf');
      expect(dangerous).toContain('sudo');
    });
  });

  describe('addDangerousCommand', () => {
    it('should add new dangerous command pattern', () => {
      executor.addDangerousCommand('dangerous-cmd');
      expect(executor.isDangerous('dangerous-cmd test')).toBe(true);
    });

    it('should not add duplicate patterns', () => {
      const initialLength = executor.getDangerousCommands().length;
      executor.addDangerousCommand('sudo');
      expect(executor.getDangerousCommands().length).toBe(initialLength);
    });
  });

  describe('execute', () => {
    it('should throw error for non-string command', async () => {
      await expect(executor.execute(null)).rejects.toThrow('Command must be a non-empty string');
      await expect(executor.execute(123)).rejects.toThrow('Command must be a non-empty string');
    });

    it('should throw error for dangerous commands', async () => {
      await expect(executor.execute('rm -rf /')).rejects.toThrow('Dangerous command detected');
      await expect(executor.execute('sudo apt-get install')).rejects.toThrow('Dangerous command detected');
    });

    it('should execute safe commands', async () => {
      // Note: This test actually executes a command, so we use a simple safe one
      try {
        const result = await executor.execute('echo "test"');
        
        expect(result.success).toBe(true);
        expect(result.command).toBe('echo "test"');
        expect(result.stdout).toContain('test');
        expect(result.exitCode).toBe(0);
      } catch (error) {
        // Skip test if shell is not available in test environment
        if (error.message.includes('Shell not found')) {
          console.log('Skipping test: shell not available');
          return;
        }
        throw error;
      }
    });

    it('should handle command failures', async () => {
      try {
        const result = await executor.execute('exit 1');
        
        expect(result.success).toBe(false);
        expect(result.exitCode).toBe(1);
      } catch (error) {
        // Skip test if shell is not available in test environment
        if (error.message.includes('Shell not found')) {
          console.log('Skipping test: shell not available');
          return;
        }
        throw error;
      }
    });

    it('should use custom working directory', async () => {
      const result = await executor.execute('pwd', { cwd: '/tmp' });
      
      expect(result.success).toBe(true);
      expect(result.stdout).toContain('tmp');
    });

    it('should handle non-existent commands', async () => {
      try {
        const result = await executor.execute('nonexistentcommand12345');
        
        expect(result.success).toBe(false);
        expect(result.error).toBeDefined();
      } catch (error) {
        // Command may throw if shell can't find it
        expect(error.message).toBeDefined();
      }
    });
  });
});
